import{c as a,Q as s,j as t,m as e}from"./chunks/framework.Bhbi9jCp.js";const A=JSON.parse('{"title":"Android 平台基础写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"androidPlatformLearning/00-写作计划.md","filePath":"androidPlatformLearning/00-写作计划.md","lastUpdated":1779789238000}'),o={name:"androidPlatformLearning/00-写作计划.md"};function i(r,n,l,p,d,c){return s(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="android-平台基础写作计划" tabindex="-1">Android 平台基础写作计划 <a class="header-anchor" href="#android-平台基础写作计划" aria-label="Permalink to &quot;Android 平台基础写作计划&quot;">​</a></h1><blockquote><p>本系列与 <strong>androidNativeLearning(现代 Android 原生开发)</strong> 是<strong>互补关系</strong>,不是替代。前者讲&quot;用 Kotlin + Compose 写应用&quot;,这一套讲&quot;Android 操作系统本身怎么工作 + 那些任何时代都要懂的平台 API&quot;。</p></blockquote><hr><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>让一个会写代码的人,理解 Android 不只是&quot;打开 Android Studio 写 Activity&quot;,而是一个完整的操作系统:Linux 内核 + AOSP 中间层 + ART + Binder + 系统服务 + 四大组件 + UI 系统。</strong></p><p>读者画像:</p><ul><li>已经会编程,但 Android 印象停在&quot;Activity 是个屏幕、XML 是布局、Intent 跳转&quot;</li><li>想读懂 AOSP 源码 / 第三方 SDK / 老开源项目的代码</li><li>想能用 ADB / Profiler / Systrace / Perfetto 排查问题</li><li>想理解 Compose / Hilt / WorkManager 这些现代库<strong>底下</strong>到底在调什么 系统服务</li><li>不限于&quot;现代应用开发&quot;——既要懂 Binder Looper ART,也要懂 Activity 生命周期 / XML View / SQLiteOpenHelper(读老代码)</li></ul><hr><h2 id="统一心智-贯穿-22-章" tabindex="-1">统一心智(贯穿 22 章) <a class="header-anchor" href="#统一心智-贯穿-22-章" aria-label="Permalink to &quot;统一心智(贯穿 22 章)&quot;">​</a></h2><blockquote><p><strong>Android 是一组运行在自己 UID 沙箱内的进程,通过 Binder IPC 与系统服务对话,由 ActivityManagerService 编排生命周期,在 ART 上跑字节码,通过 Handler/Looper 派发事件,通过 View 树绘制 UI。</strong></p></blockquote><p>这句话压住整本。每一篇都是它的具体展开:</p><ul><li><strong>&quot;运行在自己 UID 沙箱&quot;</strong> → 03 进程沙箱、20 安全模型</li><li><strong>&quot;Binder IPC 与系统服务对话&quot;</strong> → 04 Binder、05 系统服务</li><li><strong>&quot;AMS 编排生命周期&quot;</strong> → 07 Activity、09 Service</li><li><strong>&quot;ART 上跑字节码&quot;</strong> → 02 APK、06 ART</li><li><strong>&quot;Handler/Looper 派发事件&quot;</strong> → 12 Handler/Looper、13 ANR</li><li><strong>&quot;View 树绘制 UI&quot;</strong> → 14-16 View 三章</li><li><strong>&quot;老开源代码读得懂&quot;</strong> → 08 Fragment、18 旧存储、13 异步演化</li></ul><hr><h2 id="_22-章地图" tabindex="-1">22 章地图 <a class="header-anchor" href="#_22-章地图" aria-label="Permalink to &quot;22 章地图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>第一篇:Android 操作系统(6 章)</span></span>
<span class="line"><span>  01  Android 的世界观:Linux + AOSP + ART + APK 心智</span></span>
<span class="line"><span>  02  APK 解剖:Manifest / DEX / 资源 / 签名</span></span>
<span class="line"><span>  03  进程、Sandbox 与 UID 模型</span></span>
<span class="line"><span>  04  Binder:Android IPC 的物理根</span></span>
<span class="line"><span>  05  系统服务架构:SystemServer / AMS / WMS / PMS</span></span>
<span class="line"><span>  06  ART / Dalvik:GC、JIT、AOT 与字节码</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二篇:四大组件(5 章)</span></span>
<span class="line"><span>  07  Activity 生命周期与 Task / Back Stack</span></span>
<span class="line"><span>  08  Fragment:历史、问题与心智</span></span>
<span class="line"><span>  09  Service:三种形态与后台限制收紧史</span></span>
<span class="line"><span>  10  BroadcastReceiver:显式 / 隐式 / API 26 之后</span></span>
<span class="line"><span>  11  ContentProvider:URI 协议与跨进程数据共享</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三篇:线程与异步(2 章)</span></span>
<span class="line"><span>  12  Handler / Looper / MessageQueue / Choreographer</span></span>
<span class="line"><span>  13  ANR、卡顿与 Java 时代异步演化(AsyncTask / Loader / RxJava)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第四篇:UI(4 章)</span></span>
<span class="line"><span>  14  View / ViewGroup 与绘制三阶段</span></span>
<span class="line"><span>  15  XML 布局、findViewById 与 ViewBinding</span></span>
<span class="line"><span>  16  自定义 View:onMeasure / onLayout / onDraw</span></span>
<span class="line"><span>  17  资源系统:res / values-* 限定符与主题继承</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第五篇:数据与平台 API(2 章)</span></span>
<span class="line"><span>  18  旧式存储:SharedPreferences / 文件 / SQLite(SQLiteOpenHelper)</span></span>
<span class="line"><span>  19  ContentResolver / MediaStore / FileProvider(旧路径)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第六篇:安全与排障(3 章)</span></span>
<span class="line"><span>  20  Android 安全模型:权限 / 签名 / Sandbox / SELinux</span></span>
<span class="line"><span>  21  内存与泄漏:Java 引用模型 + LeakCanary 心智</span></span>
<span class="line"><span>  22  性能与调试工具:Profiler / Systrace / Perfetto / strace / ADB 实战</span></span></code></pre></div><p><strong>与现代版的衔接</strong>:</p><table tabindex="0"><thead><tr><th>现代版讲</th><th>本系列讲</th></tr></thead><tbody><tr><td><code>setContent { App() }</code> 的 Compose 树</td><td>View 树绘制的物理底层(14-16)</td></tr><tr><td><code>viewModelScope.launch { }</code> 协程</td><td>Handler/Looper 的事件循环(12)、AsyncTask 时代的演化(13)</td></tr><tr><td><code>@HiltAndroidApp</code> 与 <code>@AndroidEntryPoint</code></td><td>Application 进程模型(03)、Activity 生命周期细节(07)</td></tr><tr><td><code>WorkManager</code> 后台任务</td><td>Service 三种形态与后台限制史(09)、Binder 跨进程(04)</td></tr><tr><td><code>MainActivity</code> 单 Activity</td><td>Activity / Fragment / Task Stack 全貌(07-08)</td></tr><tr><td>Room</td><td>SQLiteOpenHelper 心智(18)</td></tr><tr><td>Photo Picker</td><td>ContentResolver / MediaStore 旧路径(19)</td></tr><tr><td>Hilt</td><td>进程注入入口的本质(03、05)</td></tr></tbody></table><p>读完本系列,你<strong>回头看现代版的每个 Jetpack 库都是它的演化版本</strong>——不再是黑盒。</p><hr><h2 id="写作风格" tabindex="-1">写作风格 <a class="header-anchor" href="#写作风格" aria-label="Permalink to &quot;写作风格&quot;">​</a></h2><p>继承现代版的强约束:</p><ol><li>开篇一句话压住核心 claim,不超 40 字</li><li>章节标题用「一、二、三」,不用学究腔</li><li>段落 ≤ 150 字,长段必拆</li><li>强观点直接说,不藏着掖着</li><li>每章结尾的&quot;踩坑&quot;对应真实事故场景</li><li>看老代码、看 AOSP 源码、用 ADB 实操都给具体命令,不空讲</li><li><strong>&quot;为什么这件事在现代 Android 还重要&quot;</strong> 是每一章的必答题——避免讲一堆&quot;已被淘汰的知识&quot;</li></ol><hr><h2 id="不覆盖的内容" tabindex="-1">不覆盖的内容 <a class="header-anchor" href="#不覆盖的内容" aria-label="Permalink to &quot;不覆盖的内容&quot;">​</a></h2><ul><li><strong>Kotlin 语言细节、Compose、协程、Hilt、Retrofit、Room 工程用法</strong>——见现代版</li><li><strong>AOSP 编译、刷机、ROM 定制</strong>——这是 ROM 开发者的事,不是应用开发者</li><li><strong>NDK / C++ 深度</strong>——除了在 06 篇短暂提到 .so / ABI,不深入</li><li><strong>Wear OS / Auto / TV 专属 API</strong>——大屏 / 可穿戴是独立专题</li><li><strong>Android 12 以前的&quot;细节差异&quot;</strong>——只在重要历史节点(API 26 后台收紧、API 33 通知权限、API 35 edge-to-edge)出现</li></ul>`,25)])])}const g=a(o,[["render",i]]);export{A as __pageData,g as default};
